{"path": "packages/harness/src/compaction-types.test.ts", "content": "import { describe, expect, it } from "vitest";
import type { ModelMessage } from "ai";

import type {
  ActualTokenUsage,
  ActualTokenUsageInput,
  CheckpointLine,
  CheckpointMessage,
  CompactionConfig,
  CompactionResult,
  CompactionSegment,
  CompactionSummary,
  ContextUsage,
  ContinuationVariant,
  Message,
  MessageLine,
  PreparedCompaction,
  PreparedCompactionSegment,
  PreparedCompactionV2,
  PruningConfig,
  SessionFileLine,
  SessionHeaderLine,
  SessionMetadata,
  StructuredState,
  TodoItem,
} from "./compaction-types.js";

// =============================================================================
// Helper fixtures
// =============================================================================

const createMockModelMessage = (): ModelMessage => ({
  content: "test content",
  role: "user",
});

const createMockDate = (): Date => new Date("2024-01-01T00:00:00.000Z");

// =============================================================================
// Message
// =============================================================================

describe("Message", () => {
  it("accepts all required fields", () => {
    const message: Message = {
      createdAt: createMockDate(),
      id: "msg-123",
      modelMessage: createMockModelMessage(),
    };

    expect(message.createdAt).toBeInstanceOf(Date);
    expect(message.id).toBe("msg-123");
    expect(message.modelMessage.role).toBe("user");
  });

  it("accepts optional originalContent field", () => {
    const message: Message = {
      createdAt: createMockDate(),
      id: "msg-123",
      modelMessage: createMockModelMessage(),
      originalContent: "original text",
    };

    expect(message.originalContent).toBe("original text");
  });

  it("allows originalContent to be undefined", () => {
    const message: Message = {
      createdAt: createMockDate(),
      id: "msg-123",
      modelMessage: createMockModelMessage(),
    };

    expect(message.originalContent).toBeUndefined();
  });
});

// =============================================================================
// CheckpointMessage
// =============================================================================

describe("CheckpointMessage", () => {
  it("accepts all required fields", () => {
    const checkpoint: CheckpointMessage = {
      createdAt: Date.now(),
      id: "ckpt-abc123",
      isSummary: true,
      message: createMockModelMessage(),
    };

    expect(typeof checkpoint.createdAt).toBe("number");
    expect(checkpoint.id).toBe("ckpt-abc123");
    expect(checkpoint.isSummary).toBe(true);
    expect(checkpoint.message.role).toBe("user");
  });

  it("accepts optional originalContent field", () => {
    const checkpoint: CheckpointMessage = {
      createdAt: Date.now(),
      id: "ckpt-abc123",
      isSummary: false,
      message: createMockModelMessage(),
      originalContent: "preserved content",
    };

    expect(checkpoint.originalContent).toBe("preserved content");
  });

  it("allows isSummary to be false", () => {
    const checkpoint: CheckpointMessage = {
      createdAt: Date.now(),
      id: "ckpt-abc123",
      isSummary: false,
      message: createMockModelMessage(),
    };

    expect(checkpoint.isSummary).toBe(false);
  });

  it("createdAt should be a number (Date.now() format)", () => {
    const now = Date.now();
    const checkpoint: CheckpointMessage = {
      createdAt: now,
      id: "ckpt-abc123",
      isSummary: true,
      message: createMockModelMessage(),
    };

    expect(checkpoint.createdAt).toBe(now);
  });
});

// =============================================================================
// SessionMetadata
// =============================================================================

describe("SessionMetadata", () => {
  it("accepts all required fields", () => {
    const metadata: SessionMetadata = {
      completionTokens: 100,
      createdAt: Date.now(),
      promptTokens: 500,
      sessionId: "session-xyz",
      summaryMessageId: "msg-summary-1",
      updatedAt: Date.now(),
    };

    expect(metadata.completionTokens).toBe(100);
    expect(metadata.promptTokens).toBe(500);
    expect(metadata.sessionId).toBe("session-xyz");
    expect(metadata.summaryMessageId).toBe("msg-summary-1");
  });

  it("allows summaryMessageId to be null (no compaction yet)", () => {
    const metadata: SessionMetadata = {
      completionTokens: 0,
      createdAt: Date.now(),
      promptTokens: 0,
      sessionId: "session-xyz",
      summaryMessageId: null,
      updatedAt: Date.now(),
    };

    expect(metadata.summaryMessageId).toBeNull();
  });

  it("allows zero token counts", () => {
    const metadata: SessionMetadata = {
      completionTokens: 0,
      createdAt: Date.now(),
      promptTokens: 0,
      sessionId: "session-xyz",
      summaryMessageId: null,
      updatedAt: Date.now(),
    };

    expect(metadata.completionTokens).toBe(0);
    expect(metadata.promptTokens).toBe(0);
  });
});

// =============================================================================
// CompactionConfig
// =============================================================================

describe("CompactionConfig", () => {
  it("accepts empty object (all fields optional)", () => {
    const config: CompactionConfig = {};

    expect(config).toEqual({});
  });

  it("accepts contextLimit with zero for unlimited", () => {
    const config: CompactionConfig = {
      contextLimit: 0,
    };

    expect(config.contextLimit).toBe(0);
  });

  it("accepts contextLimit with positive value", () => {
    const config: CompactionConfig = {
      contextLimit: 128000,
    };

    expect(config.contextLimit).toBe(128000);
  });

  it("enabled defaults to false per JSDoc", () => {
    const config: CompactionConfig = {
      enabled: false,
    };

    expect(config.enabled).toBe(false);
  });

  it("accepts enabled as true", () => {
    const config: CompactionConfig = {
      enabled: true,
    };

    expect(config.enabled).toBe(true);
  });

  it("keepRecentTokens defaults to 2000 per JSDoc", () => {
    const config: CompactionConfig = {
      keepRecentTokens: 2000,
    };

    expect(config.keepRecentTokens).toBe(2000);
  });

  it("accepts custom keepRecentTokens", () => {
    const config: CompactionConfig = {
      keepRecentTokens: 4000,
    };

    expect(config.keepRecentTokens).toBe(4000);
  });

  it("maxTokens defaults to 8000 per JSDoc", () => {
    const config: CompactionConfig = {
      maxTokens: 8000,
    };

    expect(config.maxTokens).toBe(8000);
  });

  it("accepts custom maxTokens", () => {
    const config: CompactionConfig = {
      maxTokens: 16000,
    };

    expect(config.maxTokens).toBe(16000);
  });

  it("reserveTokens defaults to 2000 per JSDoc", () => {
    const config: CompactionConfig = {
      reserveTokens: 2000,
    };

    expect(config.reserveTokens).toBe(2000);
  });

  it("accepts custom reserveTokens", () => {
    const config: CompactionConfig = {
      reserveTokens: 4000,
    };

    expect(config.reserveTokens).toBe(4000);
  });

  it("speculativeStartRatio valid range is 0.15 to 0.95", () => {
    const configMin: CompactionConfig = {
      speculativeStartRatio: 0.15,
    };
    const configMax: CompactionConfig = {
      speculativeStartRatio: 0.95,
    };

    expect(configMin.speculativeStartRatio).toBe(0.15);
    expect(configMax.speculativeStartRatio).toBe(0.95);
  });

  it("thresholdRatio defaults to 0.5 per JSDoc", () => {
    const config: CompactionConfig = {
      thresholdRatio: 0.5,
    };

    expect(config.thresholdRatio).toBe(0.5);
  });

  it("accepts custom thresholdRatio", () => {
    const config: CompactionConfig = {
      thresholdRatio: 0.7,
    };

    expect(config.thresholdRatio).toBe(0.7);
  });

  it("accepts summarizeFn function", () => {
    const config: CompactionConfig = {
      summarizeFn: async (messages: ModelMessage[], previousSummary?: string) => {
        return `Summary of ${messages.length} messages. Previous: ${previousSummary ?? "none"}`;
      },
    };

    expect(typeof config.summarizeFn).toBe("function");
  });

  it("summarizeFn can be called with messages only", async () => {
    const config: CompactionConfig = {
      summarizeFn: async (messages) => `Count: ${messages.length}`,
    };

    const result = await config.summarizeFn?.([createMockModelMessage()]);
    expect(result).toBe("Count: 1");
  });

  it("summarizeFn can be called with previousSummary", async () => {
    const config: CompactionConfig = {
      summarizeFn: async (_messages, previousSummary) => `Previous: ${previousSummary}`,
    };

    const result = await config.summarizeFn?.([createMockModelMessage()], "old summary");
    expect(result).toBe("Previous: old summary");
  });

  it("accepts all fields combined", () => {
    const config: CompactionConfig = {
      contextLimit: 128000,
      enabled: true,
      keepRecentTokens: 3000,
      maxTokens: 10000,
      reserveTokens: 2500,
      speculativeStartRatio: 0.3,
      summarizeFn: async () => "summary",
      thresholdRatio: 0.6,
    };

    expect(config.contextLimit).toBe(128000);
    expect(config.enabled).toBe(true);
    expect(config.keepRecentTokens).toBe(3000);
    expect(config.maxTokens).toBe(10000);
    expect(config.reserveTokens).toBe(2500);
    expect(config.speculativeStartRatio).toBe(0.3);
    expect(config.thresholdRatio).toBe(0.6);
    expect(typeof config.summarizeFn).toBe("function");
  });
});

