      minSavingsTokens: 500,
    };

    expect(config.minSavingsTokens).toBe(500);
  });

  it("protectedToolNames accepts array of strings", () => {
    const config: PruningConfig = {
      protectedToolNames: ["read", "write", "execute"],
    };

    expect(config.protectedToolNames).toEqual(["read", "write", "execute"]);
  });

