describe("CompactionResult", () => {
  it("accepts required fields: success, tokensAfter, tokensBefore", () => {
    const result: CompactionResult = {
      success: true,
      tokensAfter: 3000,
      tokensBefore: 10000,
    };

    expect(result.success).toBe(true);
    expect(result.tokensAfter).toBe(3000);
    expect(result.tokensBefore).toBe(10000);
  });

  it("accepts success as false", () => {
    const result: CompactionResult = {
      success: false,
      tokensAfter: 10000,
      tokensBefore: 10000,
    };

    expect(result.success).toBe(false);
  });

  it("accepts optional continuationVariant", () => {
    const result: CompactionResult = {
      continuationVariant: "auto-with-replay",
